const { test, expect } = require('@playwright/test');

test('Verify header links and navigation', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002');

  const links = [
    { text: 'okwasniewski', href: '/' },
    { text: 'blog', href: '/blog' },
    { text: 'portfolio', href: '/portfolio' },
    { text: 'videos', href: '/videos' },
    { text: 'contact', href: '/contact' }
  ];

  for (const link of links) {
    const element = page.locator(`header a[href="${link.href}"]`).first();
    await expect(element).toBeVisible();
    if (link.text) {
      await expect(element).toHaveText(new RegExp(link.text, 'i'));
    }
    await element.click();
    await expect(page).toHaveURL(new RegExp(`${link.href}$`));
    // Go back to home if not already there to ensure we can click the next link
    if (link.href !== '/') {
      await page.goto('http://localhost:3002');
    }
  }
});
